import{_ as e,a}from"./chunks/05-powerbi-compliance-matrix.sZuSnCYX.js";import{_ as o,o as r,c as d,a2 as i}from"./chunks/framework.DTa47_fH.js";const g=JSON.parse('{"title":"Export BI","description":"","frontmatter":{},"headers":[],"relativePath":"export-bi.md","filePath":"export-bi.md"}'),s={name:"export-bi.md"};function n(l,t,p,c,h,u){return r(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="export-bi" tabindex="-1">Export BI <a class="header-anchor" href="#export-bi" aria-label="Permalink to &quot;Export BI&quot;">​</a></h1><p>Export BI generates a star-schema data bundle from the latest assessment results and makes it ready to load into Power BI, Tableau, or any other BI tool that can read CSV or JSON. For Power BI users, SWAO ships pre-built <code>.pbit</code> dashboard templates that connect to this bundle out of the box.</p><p>Access from the TUI main menu by pressing <strong>6</strong>, or from the command line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao export --app &lt;app-id&gt;</span></span></code></pre></div><p>For a portfolio-level export that aggregates all applications:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>swao export --portfolio</span></span></code></pre></div><hr><h2 id="dashboard-preview" tabindex="-1">Dashboard preview <a class="header-anchor" href="#dashboard-preview" aria-label="Permalink to &quot;Dashboard preview&quot;">​</a></h2><p>The single-application Power BI dashboard gives you an instant visual read of the assessment: verdict, coverage score, compliance matrix, risk register, and full signal detail -- all filterable and drillable.</p><p><img src="'+e+'" alt="Power BI dashboard overview"></p><p><img src="'+a+'" alt="Power BI compliance matrix"></p><hr><h2 id="what-the-export-bundle-contains" tabindex="-1">What the export bundle contains <a class="header-anchor" href="#what-the-export-bundle-contains" aria-label="Permalink to &quot;What the export bundle contains&quot;">​</a></h2><p>Every export produces a consistent set of files in <code>apps/&lt;id&gt;/wsp/exports/latest/</code>:</p><table tabindex="0"><thead><tr><th>File</th><th>Contents</th></tr></thead><tbody><tr><td><code>dim_app.csv</code></td><td>Application metadata: name, stack, 7R verdict, coverage score</td></tr><tr><td><code>dim_control.csv</code></td><td>Framework controls with ID, domain, and description</td></tr><tr><td><code>dim_evidence.csv</code></td><td>Evidence items with source path and type</td></tr><tr><td><code>dim_signal.csv</code></td><td>All signals with ID, severity, control mapping, and rationale</td></tr><tr><td><code>fact_pass_runs.csv</code></td><td>Per-pass run statistics: wall time, signal count, LLM token usage, cost</td></tr><tr><td><code>fact_signals.csv</code></td><td>Signal-level compliance verdict (SATISFIED / GAP / PARTIAL)</td></tr><tr><td><code>link_signal_evidence.csv</code></td><td>Many-to-many join between signals and evidence items</td></tr><tr><td><code>link_control_evidence.csv</code></td><td>Many-to-many join between controls and evidence</td></tr><tr><td>... + 9 further dimension and fact tables</td><td>Full star schema for advanced reporting</td></tr></tbody></table><p>An NDJSON mirror of every table is generated alongside the CSV files for use with tools that prefer JSON input. An XLSX rollup sheet is also included for quick review in Excel without loading the full Power BI template.</p><hr><h2 id="power-bi-templates" tabindex="-1">Power BI templates <a class="header-anchor" href="#power-bi-templates" aria-label="Permalink to &quot;Power BI templates&quot;">​</a></h2><p>SWAO ships two pre-built Power BI templates (<code>.pbit</code> files) that connect to the export bundle automatically once you set the workspace path parameter.</p><h3 id="single-application-dashboard" tabindex="-1">Single-application dashboard <a class="header-anchor" href="#single-application-dashboard" aria-label="Permalink to &quot;Single-application dashboard&quot;">​</a></h3><p>Six report pages covering one application:</p><table tabindex="0"><thead><tr><th>Page</th><th>What it shows</th></tr></thead><tbody><tr><td>Dashboard</td><td>7R verdict, coverage score, signal-outcome donut, regime gap bar chart</td></tr><tr><td>Compliance</td><td>Controls-by-regime matrix with SATISFIED / GAP / PARTIAL colour coding</td></tr><tr><td>Signals</td><td>Full signal list with severity filter, rationale text, and evidence links</td></tr><tr><td>Risks</td><td>Risk register table, risk-score bar chart, category donut</td></tr><tr><td>Auditor</td><td>Signal-level false-positive analysis, rationale coverage metrics, block-level assessments</td></tr><tr><td>Run Stats</td><td>Pass timing, LLM cost, and token breakdown per run</td></tr></tbody></table><h3 id="portfolio-dashboard" tabindex="-1">Portfolio dashboard <a class="header-anchor" href="#portfolio-dashboard" aria-label="Permalink to &quot;Portfolio dashboard&quot;">​</a></h3><p>Five report pages covering all applications in the workspace (Enterprise):</p><table tabindex="0"><thead><tr><th>Page</th><th>What it shows</th></tr></thead><tbody><tr><td>Portfolio Overview</td><td>App count, critical risk count, average coverage, 7R distribution donut, risk-ranked table</td></tr><tr><td>Compliance</td><td>Cross-app compliance matrix showing every control by framework and application</td></tr><tr><td>Signals</td><td>Portfolio-level signal browser</td></tr><tr><td>Auditor Roll-up</td><td>Aggregate rationale coverage, FP consideration rate, cross-app compliance status</td></tr><tr><td>Run Stats</td><td>Portfolio-level timing and cost summary</td></tr></tbody></table><hr><h2 id="supported-editions" tabindex="-1">Supported editions <a class="header-anchor" href="#supported-editions" aria-label="Permalink to &quot;Supported editions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Community</th><th>Consultant</th><th>Enterprise</th></tr></thead><tbody><tr><td>Star schema CSV / NDJSON export</td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td>Power BI single-app dashboard</td><td>--</td><td>Yes</td><td>Yes</td></tr><tr><td>Power BI portfolio dashboard</td><td>--</td><td>--</td><td>Yes</td></tr></tbody></table><hr><h2 id="template-guides" tabindex="-1">Template guides <a class="header-anchor" href="#template-guides" aria-label="Permalink to &quot;Template guides&quot;">​</a></h2><p>For detailed instructions on connecting the <code>.pbit</code> templates to your export bundle, parameterising queries, and refreshing data, see the template documentation:</p><ul><li><a href="./templates/AUTHORING-GUIDE">Authoring guide -- single-app</a></li><li><a href="./templates/AUTHORING-GUIDE-PORTFOLIO">Authoring guide -- portfolio</a></li><li><a href="./templates/PARAMETERISE-PBIT-QUERIES">Parameterise queries</a></li><li><a href="./templates/REFRESH-RUNBOOK">Refresh runbook</a></li></ul>',32)])])}const v=o(s,[["render",n]]);export{g as __pageData,v as default};
